import java.util.Arrays;

public class Solution {
    public static long solve(long[] nums) {
        Arrays.sort(nums, (a, b) -> Long.compare(Math.abs(a), Math.abs(b)));
        long count = 0;
        for (int i = 0; i < nums.length; i++) {
            long target = 2 * Math.abs(nums[i]);
            int low = i + 1;
            int high = nums.length - 1;
            int pos = -1;
            while (low <= high) {
                int mid = (low + high) / 2;
                long currentAbs = Math.abs(nums[mid]);
                if (currentAbs <= target) {
                    pos = mid;
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            }
            if (pos != -1) {
                count += (pos - i);
            }
        }
        return count;
    }
}
